import heapq

class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

    def __lt__(self, other):
        # Allows heap to compare ListNodes directly without needing a counter
        return self.val < other.val


def merge_k_sorted_lists(lists: list):
    heap = []
    # Push the head of each non-empty list
    for node in lists:
        if node is not None:
            heapq.heappush(heap, node)

    dummy = ListNode(0)
    current = dummy

    while heap:
        smallest = heapq.heappop(heap)
        current.next = smallest
        current = current.next
        if smallest.next is not None:
            heapq.heappush(heap, smallest.next)

    return dummy.next


def list_to_linked(arr: list):
    if not arr:
        return None
    head = ListNode(arr[0])
    curr = head
    for val in arr[1:]:
        curr.next = ListNode(val)
        curr = curr.next
    return head


def linked_to_list(head) -> list:
    result = []
    curr = head
    while curr:
        result.append(curr.val)
        curr = curr.next
    return result
